"""PDS Live Dataset Finder — deterministic per-node workflow injection.

Ported verbatim from the production node_registry.py + stage2.py. The agent
(acting as the node router) classifies a query to ONE node, then calls
load_node_workflow(node) to inject that node's exact directory-walking workflow.
This mirrors the Live Finder's get_node_config(node).workflow_steps injection;
the content here is deterministic and keyed by node_id, never improvised.

CLI usage (how the skill invokes this — Python 3 stdlib only):
    python3 pds_node_workflows.py list      # the 8 node ids + base URLs
    python3 pds_node_workflows.py <node>    # that node's workflow block
                                            # (unknown/empty falls back to geo)
"""

SUPPORTED_NODES = ('geo', 'ppi', 'lroc', 'img', 'rms', 'sbn', 'atm', 'naif')

# node_id -> the exact, fixed workflow block injected when that node is detected.
NODE_WORKFLOWS = {
"geo": "PDS NODE: Geosciences (GEO)\nBase URL: https://pds-geosciences.wustl.edu/\nData root: ''   has_mission_layer=True\n\nDIRECTORY LAYOUT & WORKFLOW NOTES:\nDirectory layout: mission/ → dataset_or_bundle/ → volume/ (PDS3) or sub-collections (PDS4)\nThis node has a mission layer. Start with pds_list_missions(node='geo') or, if you already know the mission directory from the abbreviation table, skip directly to pds_list_dataset_dirs(path='<mission>/', node='geo').\nMost queries can be answered in 3 tool calls: list_dataset_dirs → probe_datasets → inspect_collections.\n\n\nABBREVIATIONS / NAMING:\nCommon mission/instrument abbreviations:\n  Mars Express = MEX → mex/ (instruments: HRSC, OMEGA, MARSIS, PFS, SPICAM, MaRS)\n  Mars Reconnaissance Orbiter = MRO → mro/ (instruments: HiRISE, CTX, CRISM, SHARAD, MCS)\n  Mars Science Laboratory / Curiosity = MSL → msl/ (instruments: ChemCam, APXS, CheMin, SAM, Mastcam, MAHLI, DAN)\n  Mars 2020 / Perseverance = M2020 → m2020/ (instruments: PIXL, SHERLOC, Mastcam-Z, SuperCam, RIMFAX)\n  Mars Exploration Rovers (Spirit=MER2, Opportunity=MER1) → mer/ (instruments: Pancam, Mini-TES/MTES, APXS, MB, MI)\n  Mars Global Surveyor = MGS → mgs/ (instruments: MOC, MOLA, TES, MAG)\n  Mars Odyssey = ODY → ody/ (instruments: THEMIS, GRS, NS)\n  Phoenix = PHX → phx/ (instruments: TEGA, MECA, SSI, OM, RAC)\n  Viking = VL1/VL2/VO1/VO2 → viking/ (instruments: camera, IRTM, MAWD)\n  MESSENGER = MESS → messenger/ (instruments: MDIS, GRNS, XRS, MLA, MASCS)\n  Magellan = MGN → mgn/ (instruments: SAR, altimetry, radiometry, emissivity)\n  LRO → lro/ (instruments: LOLA, Diviner, LROC, Mini-RF, LAMP)\n  GRAIL → grail/ (instruments: LGRS)\n  NEAR → near/ (instruments: NLR, MSI, XGRS, MAG)\n  InSight → insight/ (instruments: SEIS, HP3, RISE, IDA)\n\n\nWORKFLOW (follow these numbered steps for this node):\nStep 1: If you know the mission directory from the abbreviation table, skip directly to list_dataset_dirs(path='<mission>/', node='geo').\n        Otherwise call pds_list_missions(node='geo') first.\nStep 2: Call pds_list_dataset_dirs for the relevant mission directory. Scan names and pds_hints to identify promising datasets.\nStep 3: Call pds_probe_datasets with the most relevant paths (batch up to 20).\nStep 4: If PDS4 bundles are found, call pds_inspect_collections on top 2-3.\nStep 5: Return candidates.\nMost queries can be answered in 3 tool calls: list_dataset_dirs → probe_datasets → inspect_collections.\n\n\nSTAGE 2 (escalation-only) TOOLS FOR THIS NODE:\n  - ode_search_products_tool(target=..., instrument=..., bbox=..., pt=..., product_type=...): faceted product search across GEO/ODE holdings. Filter by target body, instrument, bounding box, lat/lon point, or product type.\n  - ode_count_products_tool(target=..., instrument=..., bbox=...): cheap count before pulling a large result set.\n  - ode_list_instruments_tool(target=...): enumerate instrument codes valid for a target.\n  - ode_list_feature_classes_tool(target=...) / ode_list_feature_names_tool(target=..., feature_class=...): gazetteer lookup for named surface features (craters, maria, etc.).\n  - ode_get_feature_bounds_tool(target=..., feature_name=...): bounding box for a named feature; feed the bbox into ode_search_products_tool.\n\nStage 2 allowed tools: ode_count_products_tool, ode_get_feature_bounds_tool, ode_list_feature_classes_tool, ode_list_feature_names_tool, ode_list_instruments_tool, ode_search_products_tool\n",
"ppi": "PDS NODE: Planetary Plasma Interactions (PPI)\nBase URL: https://pds-ppi.igpp.ucla.edu/\nData root: 'data/'   has_mission_layer=False\n\nDIRECTORY LAYOUT & WORKFLOW NOTES:\nAll ~781 datasets sit directly under data/ with no mission sub-directories.\nThe mission 'name' from pds_list_missions is the filter keyword to use with list_dataset_dirs.\n\n\nABBREVIATIONS / NAMING:\nDataset naming conventions:\n  PDS3 dirs use uppercase mission codes: MESS-, CO-, GO-, JNO-, VG1-, VG2-, MEX-, P10-, P11-, ULY-, NH-, PVO-, etc.\n  PDS4 dirs use lowercase names: cassini-, galileo-, juno-, maven-, messenger-, ulysses-, etc.\n  Both conventions exist for many missions. Use pds_list_missions to see all available missions and filter keywords.\nSlash-encoding in DATA_SET_IDs: directory names cannot contain '/' so PPI replaces it\nwith '_'. The dir 'JNO-J_SW-JAD-5-CALIBRATED-V1.0' corresponds to DATA_SET_ID\n'JNO-J/SW-JAD-5-CALIBRATED-V1.0'. When a DATA_SET_ID contains '/', look for the\ndirectory with '_' in those positions — pds_probe_datasets will return the canonical\nDATA_SET_ID with the slashes restored.\n\n\nWORKFLOW (follow these numbered steps for this node):\nStep 1: Call pds_list_missions(node='ppi') to see all available missions and their filter keywords.\nStep 2: Identify which mission(s) are relevant to the query.\nStep 3: Call pds_list_dataset_dirs(path='data/', node='ppi', filter='<mission_name>') using a `name` field from the mission list as the filter keyword (e.g. filter='cassini'\nfor PDS4, filter='CO' for PDS3 Cassini, filter='MESS' for MESSENGER). Filter is\nmandatory — ~781 entries otherwise.\n  STICK TO MISSION KEYWORDS. The `name` and PDS3-prefix fields from pds_list_missions\n  are the supported filter values. Do NOT improvise free-text filters like\n  'saturn', 'plasmoid', 'magnetotail', 'recon' — those rarely appear in directory\n  names and just produce empty listings. Filter by mission, then by instrument prefix\n  if needed (CAPS, MAG, MIMI, RPWS, INMS).\nStep 4: Call pds_probe_datasets with the most relevant paths (batch up to 20).\nStep 5: If PDS4 bundles are found, call pds_inspect_collections on top 2-3.\nStep 6: Return candidates — emit BOTH PDS3 and PDS4 identifiers when a mission has\nboth (PDS3 dirs like 'CO-S-MAG-...' and PDS4 dirs like 'cassini-mag-cal' coexist\nfor most major missions on PPI).\n\n\nSTAGE 2 (escalation-only) TOOLS FOR THIS NODE:\n  - pds4search_bundles_tool(keywords=..., investigation=..., instrument=..., target=...): cross-node PDS4 registry bundle search.\n  - pds4search_collections_tool(bundle_lid=..., keywords=..., ...): collection search; reuse the Stage 1 bundle LID as a filter when possible.\n  - pds4search_products_tool(collection_lid=..., keywords=..., ...): product-level search inside a collection.\n  - pds4search_investigations_tool / pds4search_instruments_tool / pds4search_instrument_hosts_tool / pds4search_targets_tool: context-product lookups when user-facing names need to be resolved to LIDs.\n  - pds4get_product_tool(lid=...): fetch one product label by LID.\n  - pds4crawl_context_product_tool(lid=...): walk a context product's associations to find related bundles/collections.\n\nStage 2 allowed tools: pds4crawl_context_product_tool, pds4get_product_tool, pds4search_bundles_tool, pds4search_collections_tool, pds4search_instrument_hosts_tool, pds4search_instruments_tool, pds4search_investigations_tool, pds4search_products_tool, pds4search_targets_tool\n",
"lroc": "PDS NODE: Lunar Reconnaissance Orbiter Camera (LROC)\nBase URL: https://pds.lroc.im-ldi.com/\nData root: 'data/'   has_mission_layer=False\n\nDIRECTORY LAYOUT & WORKFLOW NOTES:\nThis node has NO mission layer. Only 3 fixed dataset paths sit under data/.\nDo NOT call pds_list_missions — it will return an empty list.\nGo directly to pds_list_dataset_dirs(path='data/', node='lroc') to see all 3 datasets.\nThen probe the relevant ones with pds_probe_datasets.\nFor PDS4 bundles, use inspect_collections to get collection-level LIDs.\n\n\nABBREVIATIONS / NAMING:\nLROC datasets (3 total — each carries BOTH a PDS3 voldesc and a PDS4 bundle label):\n  LRO-L-LROC-2-EDR-V1.0   (PDS4 LID: urn:nasa:pds:lro-l-lroc-2-edr) — Experiment Data Records (raw images)\n  LRO-L-LROC-3-CDR-V1.0   (PDS4 LID: urn:nasa:pds:lro-l-lroc-3-cdr) — Calibrated Data Records\n  LRO-L-LROC-5-RDR-V1.0   (PDS4 LID: urn:nasa:pds:lro-l-lroc-5-rdr) — Reduced Data Records (derived products)\n\nInstruments: NAC (Narrow Angle Camera), WAC (Wide Angle Camera).\nSub-volumes are numbered directories (e.g. LROLRC_0001/, LROLRC_0002/) inside each dataset.\nThe PDS3 dataset_id and the PDS4 bundle LID address the same underlying data — they are equivalent.\n\n\nWORKFLOW (follow these numbered steps for this node):\nStep 1: SKIP pds_list_missions — it returns an empty list for LROC. Call pds_list_dataset_dirs(path='data/', node='lroc') directly to see all 3 datasets (EDR, CDR, RDR — each a hybrid PDS3+PDS4 directory).\nStep 2: Call pds_probe_datasets on the level(s) implied by the query (EDR=raw, CDR=calibrated, RDR=reduced/derived).\nStep 3: Call pds_inspect_collections on the relevant PDS4 bundles to get collection-level LIDs.\nStep 4: Return candidates — emit BOTH the PDS3 dataset_id and the PDS4 LID for the same data (e.g. LRO-L-LROC-5-RDR-V1.0 + urn:nasa:pds:lro-l-lroc-5-rdr).\n\nSTOP RULE — LROC granularity is the DATASET, not the image. The whole archive is just\nthree datasets (EDR/CDR/RDR). Do NOT recurse into sub-volume directories such as\nLROLRC_xxxx/, DATA/, EXTRAS/, ANAGLYPH/, BROWSE/, SHAPEFILE/, AMES_DTM/ etc. looking for\na specific feature (e.g. a named crater or pit). Feature-level retrieval is the LROC\ncatalog's job, not this finder's; the right answer for any LROC query is one or more of\nthe 3 top-level datasets and their matching PDS4 LIDs. Cap LROC traces at 4 tool calls.\n\n\nSTAGE 2 (escalation-only) TOOLS FOR THIS NODE:\n  - pds4search_bundles_tool(keywords=..., investigation=..., instrument=..., target=...): cross-node PDS4 registry bundle search.\n  - pds4search_collections_tool(bundle_lid=..., keywords=..., ...): collection search; reuse the Stage 1 bundle LID as a filter when possible.\n  - pds4search_products_tool(collection_lid=..., keywords=..., ...): product-level search inside a collection.\n  - pds4search_investigations_tool / pds4search_instruments_tool / pds4search_instrument_hosts_tool / pds4search_targets_tool: context-product lookups when user-facing names need to be resolved to LIDs.\n  - pds4get_product_tool(lid=...): fetch one product label by LID.\n  - pds4crawl_context_product_tool(lid=...): walk a context product's associations to find related bundles/collections.\n\nStage 2 allowed tools: pds4crawl_context_product_tool, pds4get_product_tool, pds4search_bundles_tool, pds4search_collections_tool, pds4search_instrument_hosts_tool, pds4search_instruments_tool, pds4search_investigations_tool, pds4search_products_tool, pds4search_targets_tool\n",
"img": "PDS NODE: JPL Imaging Node (IMG)\nBase URL: https://planetarydata.jpl.nasa.gov/\nData root: 'img/data/'   has_mission_layer=True\n\nDIRECTORY LAYOUT & WORKFLOW NOTES:\nDirectory layout: img/data/<mission>/[<sub-tree>/]<dataset_or_bundle>/\nTop level under img/data/ is a flat list of mission directories. Many missions nest one or\ntwo more levels before reaching dataset roots (Cassini is the most extreme — four parallel\nsub-trees). Recurse with list_dataset_dirs rather than guessing paths.\nThere is no holdings/inventory page — the Apache directory listing is the only index.\nPDS4 coverage at IMG is partial: for some missions the legacy PDS3 volumes are mirrored\nhere but the equivalent urn:nasa:pds:<mission>_<inst>_* PDS4 bundles live at a different\ndiscipline node. If a urn: LID does not turn up after one list+probe, return the closest\nPDS3 DATA_SET_ID you found while probing and note that IMG hosts the PDS3 mirror only.\n\n\nABBREVIATIONS / NAMING:\nNaming conventions on IMG:\n  Top level: lowercase mission directories (cassini/, galileo/, mariner9/, viking_orbiter/, …).\n  Inside a mission: variable structure. Cassini for example has cassini_orbiter/, opus/, pds4/, and public/ — all four can contain datasets at different depths.\n  PDS3 dataset names: hyphenated identifiers (e.g. co-s-iss-2-edr-v1.0); PDS4 bundles begin with urn-nasa-pds-.\nSkip these directories at every level when scanning: checksums, document, index, catalog,\nextras, browse, software, errata.\nVolume-numbering convention (many IMG missions follow this pattern):\n  Within a single mission/instrument directory, numbered sibling volumes encode the\n  product level (raw → calibrated → derived) in the leading digit(s) of their name.\n  Examples of the pattern (NOT a recipe for any one query):\n    MRO CTX: img/data/mro/ctx/mrox_NNNN/   — flat EDR series, all the same DATA_SET_ID.\n    MESSENGER MDIS: img/data/messenger/MDIS/MSGRMDS_<lvl><nnn>/  — leading digit splits\n      product levels (lower digit = lower processing level; higher digit = derived).\n  Use pds_resolve_volume with the relevant level keyword (EDR / CDR / RDR / BDR / MDR /\n  derived / calibrated) as the dataset_id_hint to land on the volume matching the query,\n  rather than probing many sibling volumes individually.\n\n\nWORKFLOW (follow these numbered steps for this node):\nStep 1: If you know the mission directory from the abbreviation table, skip directly to list_dataset_dirs(path='img/data/<mission>/', node='img'). Otherwise call pds_list_missions(node='img') first to see the mission list.\nStep 2: Call pds_list_dataset_dirs for the mission directory. If results look like another layer of organisational sub-trees (e.g. cassini_orbiter/, opus/, pds4/, public/ for Cassini, or ctx/, hirise/, marci/ for mro), call list_dataset_dirs again on the relevant sub-tree.\nStep 3: Volume-set targets — when a dataset is split across many numbered volumes inside a\nsingle parent directory, call pds_resolve_volume(volume_set_path='<parent path>/', node='img', dataset_id_hint='<DATA_SET_ID fragment>', sample=8). It returns per-child dataset_ids in one call instead of multiple sequential probes.\nStep 4: If PDS4 bundles are found, call pds_inspect_collections on top 2-3.\nStep 5: COVERAGE-GAP rule. If the target is a urn:nasa:pds: LID and no matching bundle turns up after Steps 1–4, OR if listing the mission/instrument directory returns only\nancillary content (EXTRAS/, browse/, document/) with no voldesc.cat in any probed sub-\ndirectory, then IMG most likely does not mirror that archive — many instruments have\ntheir main archive at a different discipline node (per the mission notes: HiRISE main\nRDR → GEO, MESSENGER MDIS PDS4 → PDS-Geosciences, etc.). Return the closest available\nPDS3 DATA_SET_ID (synthesised from the abbreviation table if no probe has succeeded\nyet) and note in `reasoning` that the main archive lives at the other node. Do not\nburn more than 2 extra list/probe calls hunting for the missing form.\nStep 6: Use the `dataset_ids` field on pds_probe_datasets results when a voldesc ships multiple DATA_SET_IDs — match against the full list, not just the scalar.\n\n\nSTAGE 2 (escalation-only) TOOLS FOR THIS NODE:\n  - img_search_tool(target=..., instrument=..., mission=..., time_range=..., filters=...): IMG faceted product search.\n  - img_get_facets_tool(field=...): enumerate valid facet values (instruments, missions, targets, product types) for the IMG catalog.\n  - img_get_product_tool(product_id=...): fetch metadata for one IMG product.\n  - img_count_tool(target=..., instrument=..., ...): count matches without pulling rows.\n\nStage 2 allowed tools: img_count_tool, img_get_facets_tool, img_get_product_tool, img_search_tool\n",
"rms": "PDS NODE: Ring-Moon Systems (RMS)\nBase URL: https://pds-rings.seti.org/\nData root: 'holdings/volumes/'   has_mission_layer=False\n\nDIRECTORY LAYOUT & WORKFLOW NOTES:\nTwo parallel trees:\n  PDS3 → holdings/volumes/<VOLUME_SET>/<VOLUME>/  (volume-set wraps multiple numbered volumes)\n  PDS4 → pds4/bundles/<bundle>/                   (flat list of bundles)\n\nCRITICAL — volume-set explosion warning:\n  Volume-sets (e.g. COISS_2xxx, COUVIS_0xxx_v1, HSTUx_xxxx_v1.0) contain many numbered\n  volumes (often 30-100+). Do NOT probe a volume-set directory directly — pds_probe_datasets\n  will recurse into ALL volumes and produce massive redundant output (100+ near-identical results).\n  Instead, probe a SINGLE representative volume inside the set, e.g.:\n    pds_probe_datasets(paths=['holdings/volumes/COUVIS_0xxx_v1/COUVIS_0009/'], node='rms')\n  All volumes in a set share the same dataset_id, so one probe is enough.\n  HST volumes are the exception — each volume has a unique dataset_id per HST program,\n  but you still should NOT probe the entire set. Pick 1-2 representative volumes.\n\n\nABBREVIATIONS / NAMING:\nNaming conventions on RMS:\n  PDS3 volumes use uppercase prefixes ending in _xxxx or numbered: COISS_1xxx, COVIMS_0xxx, GO_0017, EBROCC_xxxx.\n  Each prefix groups many numbered volumes (e.g. COISS_1xxx contains COISS_1001, COISS_1002, ...).\n  PDS4 bundles use lowercase descriptive names: cassini_iss, cassini_uvis, cassini_vims, etc.\nMission/instrument keys (use as filter):\n  Cassini → CO* (COISS, COUVIS, COVIMS, COCIRS, CORSS) for PDS3; cassini_* for PDS4\n  Voyager → VG_2xxx (imaging), VG_28xx (occultations), VGISS (PDS4)\n  Galileo → GO_*\n  New Horizons → NHxxLO, NHxxMV\n  Hubble → HSTI/HSTJ/HSTU/HSTN (camera era — each volume is a unique HST program)\n  Earth-based → EBROCC, ESO_*, RES_*\nCassini UVIS data types (COUVIS volumes):\n  COUVIS_0xxx     = raw + calibrated spectra/images (SPEC, SSB, CALIB, CUBE, etc.)\n  COUVIS_0xxx_v1  = older v1 publication of the same archive (V1.0 and V1.2 DATA_SET_IDs\n                    live in this tree)\n  COUVIS_8xxx     = ring stellar/solar occultation profiles\n  For UV spectroscopy of surfaces (Rhea, Enceladus, etc.), use COUVIS_0xxx (not _8xxx).\n  Early volumes in a COUVIS set can span mission-phase boundaries (Jupiter approach →\n  Saturn tour), so the first volume hosting a given DATA_SET_ID is not necessarily\n  volume _0001. Use pds_resolve_volume with a dataset_id_hint to find it automatically\n  rather than guessing.\nCassini ISS volume-sets:\n  COISS_1xxx = cruise-phase EDRs (Earth/Venus/Jupiter; DATA_SET_ID prefixed CO-J/V/E-…)\n  COISS_2xxx = Saturn-tour EDRs (the main science dataset; DATA_SET_ID CO-S-ISSNA/ISSWA-…)\n  COISS_3xxx = cartographic map products (MIDR)\n  COISS_0xxx = calibration files/software\nCassini VIMS volume-sets:\n  COVIMS_0xxx = raw image/spectral cubes. DATA_SET_ID convention uses 'QUBE' rather than\n    'EDR' in the product-level slot — canonical id is CO-E/V/J/S-VIMS-2-QUBE-V<x>.<y>.\n    If a target id uses 'EDR' for VIMS, treat the QUBE form as the equivalent dataset\n    hosted at this node.\n  COVIMS_8xxx = ring stellar/solar occultation profiles.\nMulti-DATA_SET_ID voldescs (common on Cassini):\n  COUVIS_*, COCIRS_*, COVIMS_* voldesc.cat files declare DATA_SET_ID as a list (one id per\n  product type on the volume — SSB/SPEC/CUBE/CALIB/WAV etc.). pds_probe_datasets now\n  exposes the full list in `dataset_ids`. Match the target DATA_SET_ID against this list,\n  not only the scalar `dataset_id` field (which is just the first one).\n\n\nWORKFLOW (follow these numbered steps for this node):\nStep 1: Call pds_list_missions(node='rms') to see the 23 instrument/mission filter keys.\nStep 2: Identify the SPECIFIC instrument(s) relevant to the query from the mission list:\n          - UV spectroscopy/absorption on surfaces → COUVIS (not COISS or HST)\n          - Visible imaging of rings/satellites → COISS\n          - IR spectral mapping → COVIMS\n          - Thermal spectra → COCIRS\n        Do NOT explore instruments not mentioned or implied by the query.\nStep 3 (PDS3): Call pds_list_dataset_dirs(path='holdings/volumes/', node='rms', filter='<KEY>') with a volume-set prefix from the abbreviation table (e.g. COISS, COVIMS, GO_00, VG_28, NHxxLO).\nStep 3 (PDS4): Call pds_list_dataset_dirs(path='pds4/bundles/', node='rms', filter='<key>') — flat list of named bundles (cassini_iss, cassini_uvis, cassini_vims, …).\nStep 4: Pick ONE representative volume from each relevant volume-set and probe it. Do NOT probe the volume-set directory itself — see the volume-set explosion warning above. Example: pds_probe_datasets(paths=['holdings/volumes/COISS_2xxx/COISS_2001/'], node='rms')\nStep 4b (search by DATA_SET_ID substring inside a large volume-set): When you are\ntargeting a specific DATA_SET_ID inside a volume-set with many numbered volumes, call\npds_resolve_volume(volume_set_path='holdings/volumes/<VOLUME_SET>/', node='rms',\n  dataset_id_hint='<DATA_SET_ID fragment>', sample=4) instead of probing volumes one by\none. It probes a hint-ranked sample and returns a `best_match` pointing at the first\nchild whose `dataset_ids` list contains the requested id. Useful when the first volume\nhosting a given id is not _0001 (early volumes can fall in a different mission phase).\nStep 5: For PDS4 bundles, call pds_inspect_collections on top 2-3 to get collection LIDs.\nStep 6: When the same instrument has BOTH a PDS3 volume-set and a PDS4 bundle, return BOTH candidates. Always scan `dataset_ids` (not only `dataset_id`) since Cassini voldescs ship many ids per volume. Do NOT silently drop the PDS3 form. Stay under 20 tool calls total.\n\n\nSTAGE 2 (escalation-only) TOOLS FOR THIS NODE:\n  - opus_search_tool(target=..., instrument=..., time_range=..., ring_geometry=..., observation_type=...): RMS OPUS faceted product search at the observation/granule level.\n  - opus_count_tool(...): count results before pulling them.\n  - opus_get_metadata_tool(opus_id=...): metadata for one observation.\n  - opus_get_files_tool(opus_id=..., product_type=...): file list for one observation, optionally filtered by product type (raw / calibrated / preview / geometry).\n\nStage 2 allowed tools: opus_count_tool, opus_get_files_tool, opus_get_metadata_tool, opus_search_tool\n",
"sbn": "PDS NODE: Small Bodies Node (SBN — PSI mirror)\nBase URL: https://sbnarchive.psi.edu/\nData root: 'pds3/'   has_mission_layer=True\n\nDIRECTORY LAYOUT & WORKFLOW NOTES:\nDirectory layout (PSI archive — sbnarchive.psi.edu):\n  pds3/<mission>/<DATASET_UPPER_UNDER>/   — PDS3 datasets, all-caps + underscores\n  pds4/<mission>/<lower.dot.name>/        — PDS4 bundles, dot-separated LID\nTop level under pds3/ and pds4/ are flat lists of mission directories. Each mission\ndirectory contains its dataset dirs directly OR splits into per-instrument subdirs\n(Dawn does both: pds3/dawn/{fc,grand,grav,vir}/ each have dataset dirs inside).\n\nPSI ships each dataset both as a .zip / .tar.gz archive AND as an unpacked directory of\nthe same name; we always probe the unpacked directory (the one without the archive\nextension). The pds_list_dataset_dirs filter excludes the archive files automatically\nbecause it only returns directories.\n\nUMD coverage gap — Rosetta, Stardust, Deep Impact, ICE/Halley, and most comet datasets\nlive at https://pds-smallbodies.astro.umd.edu/holdings/ (UMD's mirror), which is a\ndifferent base_url. If the query targets one of those, the agent cannot reach the data\nfrom this base_url; see SBN_UMD_FALLBACK in workflow_steps.\n\n\nABBREVIATIONS / NAMING:\nNaming conventions on SBN (PSI archive — sbnarchive.psi.edu):\n  Two parallel trees:\n    pds3/<mission>/<DATASET_UPPER_UNDERSCORE>/  — PDS3 PSI uses ALL_CAPS_WITH_UNDERSCORES\n    pds4/<mission>/<lower.dot.name>/            — PDS4 bundles, LID-style dot-separated\n\nPDS3 underscore-encoding (PSI-specific, IMPORTANT):\n  Both '-' and '/' in the canonical DATA_SET_ID become '_' in the directory name.\n  Version 'V1.0' is written 'V1_0' (the period also becomes underscore).\n  Examples:\n    Canonical DATA_SET_ID                                → PSI directory name\n    NEAR-A-NLR-5-EROS/SHAPE/GRAVITY-V1.0                 → NEAR_A_NLR_5_EROS_SHAPE_GRAVITY_V1_0/\n    HAY-A-AMICA-3-AMICAGEOM-V1.0                         → HAY_A_AMICA_3_AMICAGEOM_V1_0/\n  When a target DATA_SET_ID contains '/', map every '/' to '_' in the path AND filter on\n  the corresponding underscore-joined token (e.g. EROS/SHAPE/GRAVITY → EROS_SHAPE_GRAVITY,\n  not EROS_SHAPE_GRAVITY_V1).\n\nPDS4 dot-encoded LIDs (PSI):\n  Bundle dir name matches the LID body verbatim, with '.' preserved:\n    urn:nasa:pds:orex.otes  ↔  pds4/orex/orex.otes/\n    urn:nasa:pds:orex.ovirs ↔  pds4/orex/orex.ovirs/\n    urn:nasa:pds:orex.ola   ↔  pds4/orex/orex.ola/\n  Note: SBN PDS4 bundles use DOT separators inside the bundle LID (orex.otes), unlike\n  most other nodes which use HYPHENS (cassini-mag-cal) or UNDERSCORES (juno_mwr).\n\nDawn-specific PDS3 short codes (pds3/dawn/<inst>/<short>):\n  Dawn volume directory names are NOT full hyphenated DATA_SET_IDs. They use compact\n  DWN<phase><inst>_<band><level><rev> codes. Decode the target DATA_SET_ID into those\n  fields, then filter the listing for that decoded substring; do NOT search for the\n  full DATA_SET_ID directly.\n    Position-by-position decoding (DWN<phase><inst>_<band><level><rev>):\n      phase: C=Ceres, V=Vesta, X=cruise. Optional numeric/letter suffix indicates a\n             Ceres or Vesta sub-phase (e.g. C1/C2/C3/CS=Survey/CH=HAMO/CL=LAMO).\n      inst:  VIR=visual+IR spectrometer; FC1/FC2=framing camera (FC2 is flight); GRD=GRaND.\n      band:  V=Visible (used only for VIR); I=Infrared (used only for VIR).\n             Framing-camera and GRaND codes omit the band letter.\n      level: 1A=raw EDR; 1B=calibrated RDR (CDR-equivalent); 5=DDR / derived / mosaic.\n      rev:   trailing digit/letter for the publication revision; usually absent.\n    Worked example (hypothetical pattern, not a gold id): a target id of the form\n    DAWN-A-VIR-3-RDR-VIS-VESTA-<phase>-V1.0 decodes to phase=V<sub>, inst=VIR, band=V,\n    level=1B → filter the pds3/dawn/vir/ listing for 'DWNV' AND 'V1B' (or use\n    pds_resolve_volume with dataset_id_hint set to the target id and let it rank).\n    The same decoding applies to Ceres targets — just substitute phase=C<sub>.\n\nMission keys (use as filter; pick the subtree to list first):\n  PDS3 missions →  pds3/dawn/, pds3/near/, pds3/hayabusa/, pds3/cassini/, pds3/galileo/,\n                  pds3/ulysses/, pds3/iras/, pds3/neat/, pds3/msx/, pds3/non_mission/,\n                  pds3/multi_mission/\n  PDS4 missions →  pds4/orex/, pds4/hayabusa2/, pds4/cassini/, pds4/dawn/, pds4/galileo/,\n                  pds4/hayabusa/, pds4/iras/, pds4/msx/, pds4/ldex/, pds4/clipper/\n  UMD-only (NOT reachable from this base_url): Rosetta (ro-c, ro-a), Stardust (sd),\n                                                Deep Impact (di, dif, dii), comets/ICE/Halley.\n                                                See SBN_UMD_FALLBACK in workflow_steps.\n\n\nWORKFLOW (follow these numbered steps for this node):\nStep 1: Decide which subtree (pds3/ or pds4/) the query targets. Target ids that start\n        with 'urn:nasa:pds:' use pds4/; everything else (DAWN-*, NEAR-A-*, HAY-*, etc.)\n        uses pds3/.\nStep 2: Decide which mission directory the query targets. Use the abbreviation table:\n        DAWN target → pds3/dawn/<inst>/  (split into fc/, grand/, grav/, vir/ for PDS3)\n        NEAR target → pds3/near/         (flat list of NEAR_A_<INST>_<LEVEL>_* dirs)\n        OREX target → pds4/orex/         (flat list of orex.<instrument> bundles)\nStep 3 (PDS3 PSI): Call pds_list_dataset_dirs(path='pds3/<mission>/[<inst>/]', node='sbn',\n        filter='<token>') with a filter that matches the underscore-encoded form of the\n        target DATA_SET_ID. Pick a discriminating substring of the canonical id (an\n        instrument/level/target token, not the version suffix), convert any '-' or '/' in\n        it to '_', and use that as the filter. Then probe the matching directory.\nStep 3 (PDS4 PSI): Call pds_list_dataset_dirs(path='pds4/<mission>/', node='sbn',\n        filter='<instrument>') and pick the bundle whose name matches the LID body:\n          urn:nasa:pds:orex.otes →\n             list_dataset_dirs(path='pds4/orex/', filter='orex.otes') →\n             pick the unversioned dir 'orex.otes/' (NOT orex.otes_v10.0/ which is an\n             older snapshot; the latest is named without _vN.0).\nStep 4: pds_probe_datasets on the matched dataset path (max 1 call per id).\nStep 5: For PDS4 bundles, follow with pds_inspect_collections to get per-instrument\n        collection LIDs (urn:nasa:pds:orex.otes:data_calibrated etc.).\nStep 6: Use the `dataset_ids` field on probe_datasets — when a voldesc declares multiple\n        ids, match against the full list (rare on PSI but happens for some Dawn volumes\n        that mix VIS+IR products).\n\nSBN_UMD_FALLBACK — If the target DATA_SET_ID starts with 'ro-c-', 'ro-a-', 'sd-', 'di-',\n  'dif-', 'dii-', 'ear-', or otherwise hits one of the UMD-only missions listed above:\n    a. Do NOT spend tool calls hunting at this base_url; PSI does not host them.\n    b. Return a candidate using the abbreviation pattern\n       '<mission>-<target>-<instrument>-<level>-v<n>' and note in `reasoning` that the\n       dataset lives at UMD's mirror (pds-smallbodies.astro.umd.edu/holdings/), not\n       PSI's archive. Cap the trace at 2 tool calls in this fallback path.\n\n\nSTAGE 2 (escalation-only) TOOLS FOR THIS NODE:\n  - sbn_search_object_tool(target_name=..., target_type=...): look up data by small-body name (comet, asteroid, KBO).\n  - sbn_search_coordinates_tool(ra=..., dec=..., radius=..., epoch=...): spatial search of small-body observations near a sky position.\n  - sbn_list_sources_tool(): enumerate SBN sub-archives / mirrors when the PSI tree is unavailable (e.g. UMD mirror for Rosetta / Stardust / Deep Impact / comets).\n\nStage 2 allowed tools: sbn_list_sources_tool, sbn_search_coordinates_tool, sbn_search_object_tool\n",
"atm": "PDS NODE: Atmospheres (ATM)\nBase URL: https://pds-atmospheres.nmsu.edu/\nData root: 'PDS/data/'   has_mission_layer=False\n\nDIRECTORY LAYOUT & WORKFLOW NOTES:\nTwo parallel trees:\n  PDS3 → PDS/data/<VOLUME>/  (note: PDS/data/ also contains a `PDS4/` subdir — skip it for PDS3)\n  PDS4 → PDS/data/PDS4/<bundle>/  (Huygens, InSight, MAVEN, etc.)\nFor PDS3: pds_list_dataset_dirs(path='PDS/data/', node='atm', filter='<key>') with the abbreviation prefix.\nFor PDS4: pds_list_dataset_dirs(path='PDS/data/PDS4/', node='atm') — flat list of bundle dirs.\nMany ATM directories are HYBRID — they ship BOTH a PDS3 voldesc.cat in subdirs and a PDS4 bundle XML.\npds_probe_datasets returns one entry per label; expect duplicates with different pds_version values.\n\n\nABBREVIATIONS / NAMING:\nNaming conventions on ATM:\n  PDS3 volumes use lowercase prefixes on ATM: cocirs_0401, cors_0001, mrom_0001, etc.\n  Each prefix typically maps to one mission/instrument; volumes are numbered sequentially.\n  PDS4 bundles live under PDS/data/PDS4/ with mission-named directories (Huygens, InSight, MAVEN, etc.).\n  IMPORTANT — many PDS4 bundles are ALSO co-located INSIDE their PDS3 mirror volume\n  under PDS/data/<VOLNAME>/ (hybrid layout). When the target id is a urn:nasa:pds:<mission>\n  identifier and the top-level PDS/data/PDS4/<mission>/ directory does not exist or does\n  not contain it, always re-check the matching PDS3 volume series — the bundle XML may be\n  shipped inside one of those numbered volumes rather than under PDS/data/PDS4/.\nMission/instrument keys (use as filter on PDS/data/):\n  Cassini CIRS (thermal IR spectra) → cocirs  (~84 volumes named cocirs_<YYMM>).\n        Later/higher-numbered volumes carry the latest TSDR / CUBES revisions; use\n        pds_resolve_volume with a dataset_id_hint to land on the right one in one call.\n  Cassini Radio Science (RSS) → cors  (~430 volumes: cors_0001 … cors_04xx)\n  Cassini ISS (imaging, limited) → coiss\n  Cassini RADAR (Titan) → coradr\n  Cassini-Huygens cruise → CO_HUYGENS\n  Mars Climate Sounder (MRO) → MROM  — volume-number convention:\n        MROM_0xxx = EDR (raw, level-2),  MROM_2xxx = DDR (derived, level-5).\n        For a derived/level-5 target, resolve inside the MROM_2xxx series\n        (pds_resolve_volume with dataset_id_hint='DDR' or 'level 5').\n  Juno MWR → jnomwr  — volume-number convention:\n        jnomwr_0xxx = EDR (raw),  jnomwr_1xxx = RDR / calibrated.\n        The PDS4 bundle urn:nasa:pds:juno_mwr ships INSIDE the PDS3 hybrid tree (not\n        under PDS/data/PDS4/); the :data_calibrated collection lives inside one of the\n        jnomwr_1xxx volumes — use pds_resolve_volume(volume_set_path='PDS/data/',\n        dataset_id_hint='juno_mwr calibrated', node='atm') to find which one.\n  MAVEN → MAVENM (PDS3) or look in PDS/data/PDS4/MAVEN/ (PDS4)\n  Mars Express SPICAM → MEXSPI\n  Pioneer Venus → PVO (orbiter), PVP (probes)\n  Galileo Probe → GP\n  Voyager IRIS → VG_IRIS\n  Huygens Probe → HP (PDS3) or PDS/data/PDS4/Huygens/ (PDS4 — has ACP, DISR, DWE, GCMS, HASI, SSP, HK)\n  Mars rover weather → MSL_REMS, M2020_MEDA, PHX\n\n\nWORKFLOW (follow these numbered steps for this node):\nStep 1: Decide PDS3 vs PDS4 based on the query.\nStep 2 (PDS3): Call pds_list_dataset_dirs(path='PDS/data/', node='atm', filter='<KEY>') with a volume prefix from the abbreviation table (MROM, MAVENM, MEXSPI, PVO, GP, HP, VG_IRIS, MSL_REMS, M2020_MEDA, PHX, EARTH_, jnomwr, cocirs, cors, …). Filter is mandatory — ~2000 entries. Ignore the `PDS4/` subdirectory at this level.\nStep 2 (PDS4 — top-level bundles): Call pds_list_dataset_dirs(path='PDS/data/PDS4/', node='atm') — flat list of mission-named bundle dirs (Huygens/, InSight/, MAVEN/, …).\nStep 2-bis (PDS4 hybrids — IMPORTANT): If the target is a urn:nasa:pds:<mission> identifier and Step 2 (PDS4) didn't find a matching bundle, the bundle is most likely co-located inside the PDS3 mirror volume under PDS/data/<VOLNAME>/. Run Step 3 there.\nStep 3: When a mission spans many numbered volumes that differ by product level (e.g. jnomwr_0xxx=raw / jnomwr_1xxx=calibrated; MROM_0xxx=EDR / MROM_2xxx=DDR), call pds_resolve_volume(volume_set_path='PDS/data/', node='atm', dataset_id_hint='<target dataset_id or product type>', sample=8) instead of probing volumes one by one. The hint can be a partial DATA_SET_ID, product keyword ('calibrated', 'DDR', 'RDR'), or instrument code; the tool ranks children by hint similarity and probes the top `sample` of them in one call, returning per-child dataset_ids and a `best_match` path.\nStep 4: For PDS4 bundles (top-level OR hybrid), call pds_inspect_collections on the matched bundle path. Many bundles ship per-product collections (e.g. urn:…:juno_mwr:data_calibrated, urn:…:juno_mwr:data_raw); pick the one whose logical_identifier matches the query.\nStep 5: Use pds_probe_datasets only when you already know the specific volume path. It returns `dataset_id` (first id, scalar) AND `dataset_ids` (full list); some Cassini\nvoldescs (cocirs, cors, COVIMS, COUVIS) declare multiple ids per volume (TSDR + CUBES,\ncalibrated + raw, etc.). Always scan `dataset_ids` when matching the target id, not\nonly the scalar `dataset_id` field.\nStep 6: Return BOTH PDS3 and PDS4 IDs when the directory is hybrid.\n\n\nSTAGE 2 (escalation-only) TOOLS FOR THIS NODE:\n  - pds4search_bundles_tool(keywords=..., investigation=..., instrument=..., target=...): cross-node PDS4 registry bundle search.\n  - pds4search_collections_tool(bundle_lid=..., keywords=..., ...): collection search; reuse the Stage 1 bundle LID as a filter when possible.\n  - pds4search_products_tool(collection_lid=..., keywords=..., ...): product-level search inside a collection.\n  - pds4search_investigations_tool / pds4search_instruments_tool / pds4search_instrument_hosts_tool / pds4search_targets_tool: context-product lookups when user-facing names need to be resolved to LIDs.\n  - pds4get_product_tool(lid=...): fetch one product label by LID.\n  - pds4crawl_context_product_tool(lid=...): walk a context product's associations to find related bundles/collections.\n\nStage 2 allowed tools: pds4crawl_context_product_tool, pds4get_product_tool, pds4search_bundles_tool, pds4search_collections_tool, pds4search_instrument_hosts_tool, pds4search_instruments_tool, pds4search_investigations_tool, pds4search_products_tool, pds4search_targets_tool\n",
"naif": "PDS NODE: Navigation and Ancillary Information Facility (NAIF)\nBase URL: https://naif.jpl.nasa.gov/\nData root: 'pub/naif/pds/data/'   has_mission_layer=True\n\nDIRECTORY LAYOUT & WORKFLOW NOTES:\nTwo parallel trees:\n  PDS3 → pub/naif/pds/data/<mission_archive>/<version_dir>/   (TWO levels deep)\n  PDS4 → pub/naif/pds/pds4/<bundle>/                          (flat list)\nPDS3 archives nest the actual volume one level inside (e.g. lro-l-spice-6-v1.0/lrosp_1000/ contains the voldesc.cat). pds_probe_datasets recurses into that inner directory automatically.\nMultiple version dirs may exist (lrosp_1000/, lrosp_1001/, …) — prefer the highest-numbered version.\nNAIF is the SPICE archive: only use it for queries about ephemerides, attitude, frames, or spacecraft clocks. For measured science data (imaging, spectroscopy, fields/particles) use a discipline node instead.\n\n\nABBREVIATIONS / NAMING:\nNaming conventions on NAIF:\n  PDS3 archive root: <mission>-<target>-spice-6-v<x.y>/  (e.g. lro-l-spice-6-v1.0/).\n  Each archive root contains ONE numbered version sub-directory (e.g. lrosp_1000/, msls_1000/) which is the actual PDS3 volume holding voldesc.cat and data/, catalog/, etc.\n  PDS4 bundles use lowercase mission identifiers under pub/naif/pds/pds4/.\nKernel types stored: SPK (trajectories), CK (orientation), FK (frames), IK (instrument), LSK (leapseconds), PCK (planetary constants), SCLK (spacecraft clocks). Only relevant when the query is about geometry/pointing/timing rather than measured science data.\nSkip these directories when scanning: checksums, extras, browse, software, errata, document, index, catalog.\n\n\nWORKFLOW (follow these numbered steps for this node):\nStep 1: Confirm the query is actually about SPICE / geometry / pointing / timing — if it's about measured science data, use a discipline node (GEO/PPI/RMS/IMG/etc.) instead.\nStep 2: Decide PDS3 vs PDS4. Most NAIF papers cite the PDS3 archive id (e.g. LRO-L-SPICE-6-V1.0); PDS4 bundles are the modern equivalent.\nStep 3 (PDS3): Call pds_list_dataset_dirs(path='pub/naif/pds/data/', node='naif', filter='<mission>') with a mission key from the abbreviation table.\nStep 3 (PDS4): Call pds_list_dataset_dirs(path='pub/naif/pds/pds4/', node='naif') — flat list of bundles.\nStep 4: Call pds_probe_datasets on the relevant archive root(s). For PDS3, the tool automatically recurses into the inner numbered version directory to find voldesc.cat; when multiple version dirs exist, prefer the highest version (e.g. lrosp_1001 over lrosp_1000).\nStep 5: For PDS4 bundles, call pds_inspect_collections on top 2-3.\nStep 6: Return BOTH PDS3 archive id and PDS4 bundle LID when both exist for the same mission.\n\n\nSTAGE 2 (escalation-only) TOOLS FOR THIS NODE:\n  - pds4search_bundles_tool(keywords=..., investigation=..., instrument=..., target=...): cross-node PDS4 registry bundle search.\n  - pds4search_collections_tool(bundle_lid=..., keywords=..., ...): collection search; reuse the Stage 1 bundle LID as a filter when possible.\n  - pds4search_products_tool(collection_lid=..., keywords=..., ...): product-level search inside a collection.\n  - pds4search_investigations_tool / pds4search_instruments_tool / pds4search_instrument_hosts_tool / pds4search_targets_tool: context-product lookups when user-facing names need to be resolved to LIDs.\n  - pds4get_product_tool(lid=...): fetch one product label by LID.\n  - pds4crawl_context_product_tool(lid=...): walk a context product's associations to find related bundles/collections.\n\nStage 2 allowed tools: pds4crawl_context_product_tool, pds4get_product_tool, pds4search_bundles_tool, pds4search_collections_tool, pds4search_instrument_hosts_tool, pds4search_instruments_tool, pds4search_investigations_tool, pds4search_products_tool, pds4search_targets_tool\n"
}


def load_node_workflow(node: str) -> str:
    """Return the authoritative, fixed directory-walking workflow for ONE PDS
    discipline node. Call this immediately after you classify the query to a
    node. `node` must be one of: geo, ppi, lroc, img, rms, sbn, atm, naif.

    The returned text is the single source of truth for how to traverse that
    node's archive with the Stage 1 MCP tools (always pass node=<id>) and, if
    you must escalate, which Stage 2 tools that node allows. Follow it exactly.
    Unknown/empty input falls back to GEO (the Live Finder's fallback node).
    """
    key = (node or "").strip().lower()
    if key not in NODE_WORKFLOWS:
        key = "geo"
    return NODE_WORKFLOWS[key]


def list_supported_nodes() -> str:
    """List the 8 supported PDS discipline node IDs and their archive base URLs,
    to help map a classified query to the right node before loading its workflow."""
    return "\n".join(NODE_NODE_SUMMARY)

NODE_NODE_SUMMARY = [
"geo: Geosciences (GEO) — https://pds-geosciences.wustl.edu/",
"ppi: Planetary Plasma Interactions (PPI) — https://pds-ppi.igpp.ucla.edu/",
"lroc: Lunar Reconnaissance Orbiter Camera (LROC) — https://pds.lroc.im-ldi.com/",
"img: JPL Imaging Node (IMG) — https://planetarydata.jpl.nasa.gov/",
"rms: Ring-Moon Systems (RMS) — https://pds-rings.seti.org/",
"sbn: Small Bodies Node (SBN — PSI mirror) — https://sbnarchive.psi.edu/",
"atm: Atmospheres (ATM) — https://pds-atmospheres.nmsu.edu/",
"naif: Navigation and Ancillary Information Facility (NAIF) — https://naif.jpl.nasa.gov/"
]


if __name__ == "__main__":
    import sys

    arg = sys.argv[1].strip().lower() if len(sys.argv) > 1 else ""
    if arg in ("list", "--list", "nodes"):
        print(list_supported_nodes())
    elif arg:
        print(load_node_workflow(arg))
    else:
        print("usage: python3 pds_node_workflows.py list|<node>", file=sys.stderr)
        print("nodes: " + ", ".join(SUPPORTED_NODES), file=sys.stderr)
        sys.exit(2)
